import { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useCart } from '../context/CartContext';
import CartSidebar from '../components/CartSidebar';

// ── Static menu data (replace with API call later) ──────────────────────────
const MENU_DATA = {
  'spice-garden': {
    categories: ['Starters', 'Main Course', 'Breads', 'Rice & Biryani', 'Beverages', 'Desserts'],
    items: [
      { id: 'sg1', name: 'Veg Seekh Kebab',    price: 180, emoji: '🥗',  isVeg: true,  category: 'Starters',      desc: 'Spiced cottage cheese & vegetables grilled in tandoor. Served with mint chutney.' },
      { id: 'sg2', name: 'Chicken Tikka',       price: 280, emoji: '🍗',  isVeg: false, category: 'Starters',      desc: 'Marinated chicken pieces grilled in tandoor with aromatic spices and yogurt.' },
      { id: 'sg3', name: 'Paneer Tikka',        price: 220, emoji: '🧀',  isVeg: true,  category: 'Starters',      desc: 'Fresh cottage cheese marinated overnight in yogurt, ginger and spices.' },
      { id: 'sg4', name: 'Dal Makhani',         price: 160, emoji: '🍲',  isVeg: true,  category: 'Main Course',   desc: 'Slow cooked black lentils simmered overnight in butter, cream and tomato.' },
      { id: 'sg5', name: 'Butter Chicken',      price: 280, emoji: '🍛',  isVeg: false, category: 'Main Course',   desc: 'Tender chicken in rich tomato-based butter gravy. A classic Punjabi dish.' },
      { id: 'sg6', name: 'Palak Paneer',        price: 200, emoji: '🥬',  isVeg: true,  category: 'Main Course',   desc: 'Cottage cheese cubes in smooth spiced spinach gravy.' },
      { id: 'sg7', name: 'Garlic Naan',         price: 40,  emoji: '🫓',  isVeg: true,  category: 'Breads',        desc: 'Soft leavened bread baked in tandoor with garlic and butter.' },
      { id: 'sg8', name: 'Butter Roti',         price: 30,  emoji: '🫓',  isVeg: true,  category: 'Breads',        desc: 'Whole wheat flatbread served with butter.' },
      { id: 'sg9', name: 'Veg Biryani',         price: 180, emoji: '🍚',  isVeg: true,  category: 'Rice & Biryani', desc: 'Fragrant basmati rice cooked with mixed vegetables and whole spices.' },
      { id: 'sg10', name: 'Chicken Biryani',    price: 250, emoji: '🍚',  isVeg: false, category: 'Rice & Biryani', desc: 'Slow-cooked basmati rice layered with marinated chicken.' },
      { id: 'sg11', name: 'Masala Chai',        price: 40,  emoji: '🫖',  isVeg: true,  category: 'Beverages',     desc: 'Classic Indian spiced tea with ginger, cardamom and fresh milk.' },
      { id: 'sg12', name: 'Mango Lassi',        price: 80,  emoji: '🥭',  isVeg: true,  category: 'Beverages',     desc: 'Chilled yogurt-based drink blended with sweet Alphonso mangoes.' },
      { id: 'sg13', name: 'Gulab Jamun',        price: 80,  emoji: '🍮',  isVeg: true,  category: 'Desserts',      desc: 'Soft milk dumplings soaked in rose-flavoured sugar syrup. Served warm.' },
      { id: 'sg14', name: 'Kulfi Falooda',      price: 120, emoji: '🍨',  isVeg: true,  category: 'Desserts',      desc: 'Traditional Indian ice cream with rose syrup, basil seeds and vermicelli.' },
    ],
  },
  'burger-republic': {
    categories: ['Burgers', 'Sides', 'Beverages', 'Combos'],
    items: [
      { id: 'br1', name: 'Classic Chicken Burger', price: 180, emoji: '🍔', isVeg: false, category: 'Burgers', desc: 'Crispy fried chicken fillet, lettuce, tomato, cheddar and house sauce.' },
      { id: 'br2', name: 'Veg Aloo Tikki Burger',  price: 120, emoji: '🍔', isVeg: true,  category: 'Burgers', desc: 'Spiced potato patty with onion, chutney and fresh veggies.' },
      { id: 'br3', name: 'Double Smash Burger',     price: 280, emoji: '🍔', isVeg: false, category: 'Burgers', desc: 'Two smashed beef patties, double cheddar, caramelised onions, pickles.' },
      { id: 'br4', name: 'Crispy Fries',            price: 80,  emoji: '🍟', isVeg: true,  category: 'Sides',   desc: 'Golden crispy fries seasoned with our signature spice mix.' },
      { id: 'br5', name: 'Onion Rings',             price: 90,  emoji: '🧅', isVeg: true,  category: 'Sides',   desc: 'Beer-battered onion rings, crispy outside, soft inside.' },
      { id: 'br6', name: 'Coca-Cola',               price: 50,  emoji: '🥤', isVeg: true,  category: 'Beverages', desc: '330ml chilled can.' },
      { id: 'br7', name: 'Thick Shake',             price: 120, emoji: '🥤', isVeg: true,  category: 'Beverages', desc: 'Choose from chocolate, vanilla or strawberry. Served thick and cold.' },
      { id: 'br8', name: 'Burger + Fries + Drink',  price: 280, emoji: '🍱', isVeg: false, category: 'Combos',    desc: 'Classic chicken burger with crispy fries and a can of your choice.' },
    ],
  },
  'dragon-wok': {
    categories: ['Starters', 'Noodles & Rice', 'Main Course', 'Soups', 'Beverages'],
    items: [
      { id: 'dw1', name: 'Veg Spring Rolls',      price: 120, emoji: '🥢', isVeg: true,  category: 'Starters',        desc: 'Crispy rolls stuffed with stir-fried vegetables. Served with sweet chilli sauce.' },
      { id: 'dw2', name: 'Chicken Manchurian',     price: 200, emoji: '🍗', isVeg: false, category: 'Starters',        desc: 'Deep fried chicken in a spicy Manchurian sauce. Dry or with gravy.' },
      { id: 'dw3', name: 'Veg Fried Rice',         price: 160, emoji: '🍚', isVeg: true,  category: 'Noodles & Rice',  desc: 'Wok-tossed basmati rice with fresh vegetables and soy sauce.' },
      { id: 'dw4', name: 'Chicken Hakka Noodles', price: 180, emoji: '🍜', isVeg: false, category: 'Noodles & Rice',  desc: 'Hand-pulled noodles stir-fried with chicken and vegetables in dark soy.' },
      { id: 'dw5', name: 'Paneer Schezwan',        price: 220, emoji: '🧀', isVeg: true,  category: 'Main Course',     desc: 'Cottage cheese in fiery Schezwan sauce with bell peppers and onions.' },
      { id: 'dw6', name: 'Hot and Sour Soup',      price: 100, emoji: '🍵', isVeg: true,  category: 'Soups',           desc: 'Classic Chinese soup with tofu, mushroom and vinegar kick.' },
      { id: 'dw7', name: 'Green Tea',              price: 60,  emoji: '🍵', isVeg: true,  category: 'Beverages',       desc: 'Freshly brewed authentic green tea.' },
    ],
  },
  'pizza-co': {
    categories: ['Pizzas', 'Sides', 'Beverages', 'Desserts'],
    items: [
      { id: 'pc1', name: 'Margherita',         price: 220, emoji: '🍕', isVeg: true,  category: 'Pizzas',    desc: 'Classic tomato sauce, fresh mozzarella, basil. Simple. Perfect.' },
      { id: 'pc2', name: 'BBQ Chicken',        price: 320, emoji: '🍕', isVeg: false, category: 'Pizzas',    desc: 'Smoky BBQ sauce, grilled chicken, red onions, cheddar.' },
      { id: 'pc3', name: 'Veggie Supreme',     price: 280, emoji: '🍕', isVeg: true,  category: 'Pizzas',    desc: 'Bell peppers, mushrooms, olives, corn, jalapeño and mozzarella.' },
      { id: 'pc4', name: 'Garlic Bread',       price: 80,  emoji: '🥖', isVeg: true,  category: 'Sides',     desc: 'Wood-fired garlic bread with herb butter and parmesan.' },
      { id: 'pc5', name: 'Pepsi',              price: 50,  emoji: '🥤', isVeg: true,  category: 'Beverages', desc: '330ml chilled can.' },
      { id: 'pc6', name: 'Choco Lava Cake',   price: 140, emoji: '🍫', isVeg: true,  category: 'Desserts',  desc: 'Warm chocolate cake with a gooey molten centre. Served with vanilla ice cream.' },
    ],
  },
  'chai-snacks': {
    categories: ['Chai & Coffee', 'Snacks', 'Sandwiches'],
    items: [
      { id: 'cs1', name: 'Masala Chai',        price: 30,  emoji: '🫖', isVeg: true, category: 'Chai & Coffee', desc: 'Our signature spiced tea brewed with fresh ginger and cardamom.' },
      { id: 'cs2', name: 'Cold Coffee',        price: 80,  emoji: '☕', isVeg: true, category: 'Chai & Coffee', desc: 'Chilled coffee blended with milk and ice cream.' },
      { id: 'cs3', name: 'Samosa (2 pcs)',     price: 40,  emoji: '🥟', isVeg: true, category: 'Snacks',        desc: 'Crispy pastry filled with spiced potatoes and peas.' },
      { id: 'cs4', name: 'Veg Puff',           price: 30,  emoji: '🥐', isVeg: true, category: 'Snacks',        desc: 'Flaky puff pastry stuffed with spiced mixed vegetables.' },
      { id: 'cs5', name: 'Grilled Sandwich',   price: 80,  emoji: '🥪', isVeg: true, category: 'Sandwiches',    desc: 'Cheese, tomato, capsicum and corn grilled sandwich.' },
    ],
  },
  'biryani-hub': {
    categories: ['Biryani', 'Starters', 'Curries', 'Beverages'],
    items: [
      { id: 'bh1', name: 'Hyderabadi Chicken Biryani', price: 280, emoji: '🍛', isVeg: false, category: 'Biryani',    desc: 'Slow-cooked dum biryani with marinated chicken, saffron and caramelised onions.' },
      { id: 'bh2', name: 'Mutton Biryani',             price: 380, emoji: '🍛', isVeg: false, category: 'Biryani',    desc: 'Tender mutton pieces layered with fragrant basmati rice and whole spices.' },
      { id: 'bh3', name: 'Veg Biryani',                price: 180, emoji: '🍚', isVeg: true,  category: 'Biryani',    desc: 'Mixed vegetable dum biryani with paneer and whole spices.' },
      { id: 'bh4', name: 'Chicken 65',                 price: 220, emoji: '🍗', isVeg: false, category: 'Starters',   desc: 'Spicy deep-fried chicken, a Hyderabadi classic.' },
      { id: 'bh5', name: 'Raita',                      price: 60,  emoji: '🥛', isVeg: true,  category: 'Curries',    desc: 'Chilled yogurt with cucumber, cumin and herbs.' },
      { id: 'bh6', name: 'Mirchi Ka Salan',            price: 80,  emoji: '🫙', isVeg: true,  category: 'Curries',    desc: 'Hyderabadi peanut and sesame-based gravy with long chillies.' },
      { id: 'bh7', name: 'Sweet Lassi',                price: 70,  emoji: '🥛', isVeg: true,  category: 'Beverages',  desc: 'Thick chilled yogurt drink lightly sweetened.' },
    ],
  },
};

export default function Menu() {
  const { restaurantInfo, cart, addItem, removeItem } = useCart();
  const [activeCategory, setActiveCategory] = useState(null);
  const [search, setSearch] = useState('');
  const navigate = useNavigate();

  // Fallback if someone navigates directly
  const restId   = restaurantInfo?.id || 'spice-garden';
  const menuData = MENU_DATA[restId] || MENU_DATA['spice-garden'];
  const categories = menuData.categories;

  const currentCat = activeCategory || categories[0];

  const visibleItems = menuData.items.filter(item => {
    const matchCat    = item.category === currentCat;
    const matchSearch = item.name.toLowerCase().includes(search.toLowerCase()) ||
                        item.desc.toLowerCase().includes(search.toLowerCase());
    return search ? matchSearch : matchCat;
  });

  return (
    <div className="flex h-[calc(100vh-64px)]">

      {/* ── Category sidebar ── */}
      <aside className="w-52 bg-white border-r border-gray-100 flex-shrink-0 overflow-y-auto">
        <div className="px-4 pt-5 pb-2">
          <p className="text-xs font-semibold text-gray-400 uppercase tracking-wider">Menu</p>
        </div>
        {categories.map(cat => {
          const count = menuData.items.filter(i => i.category === cat).length;
          return (
            <button
              key={cat}
              onClick={() => { setActiveCategory(cat); setSearch(''); }}
              className={`w-full text-left px-4 py-3 text-sm flex justify-between items-center border-l-4 transition-colors ${
                currentCat === cat && !search
                  ? 'border-red-500 bg-red-50 text-red-600 font-semibold'
                  : 'border-transparent text-gray-600 hover:bg-gray-50'
              }`}
            >
              {cat}
              <span className="text-xs bg-gray-100 text-gray-500 rounded-full px-2 py-0.5">
                {count}
              </span>
            </button>
          );
        })}
      </aside>

      {/* ── Main menu area ── */}
      <main className="flex-1 overflow-y-auto bg-gray-50">
        {/* Header */}
        <div className="bg-white border-b border-gray-100 px-6 py-4 flex items-center gap-4 sticky top-0 z-10">
          <button
            onClick={() => navigate('/restaurants')}
            className="text-sm text-gray-500 hover:text-gray-800 border border-gray-200 px-3 py-1.5 rounded-lg bg-gray-50 hover:bg-gray-100 transition-colors"
          >
            ← Back
          </button>
          <div className="flex-1">
            <h1 className="font-bold text-gray-900">
              {restaurantInfo?.name || 'Restaurant Menu'}
            </h1>
            <p className="text-xs text-gray-500 mt-0.5">
              {restaurantInfo?.cuisine || ''} · ★ {restaurantInfo?.rating || '4.5'} · {restaurantInfo?.time || '25–30 min'}
            </p>
          </div>
          {/* Search */}
          <input
            type="text"
            value={search}
            onChange={e => setSearch(e.target.value)}
            placeholder="Search menu..."
            className="w-52 px-4 py-2 border border-gray-200 rounded-full text-sm bg-gray-50 focus:outline-none focus:ring-2 focus:ring-red-500 focus:border-transparent"
          />
        </div>

        {/* Items */}
        <div className="px-6 py-5">
          {!search && (
            <h2 className="text-base font-semibold text-gray-800 mb-4 pb-3 border-b border-gray-200">
              {currentCat}
              <span className="text-sm font-normal text-gray-400 ml-2">
                ({visibleItems.length} items)
              </span>
            </h2>
          )}

          {search && (
            <p className="text-sm text-gray-500 mb-4">
              Showing results for "<strong>{search}</strong>" ({visibleItems.length} found)
            </p>
          )}

          {visibleItems.length === 0 ? (
            <div className="text-center py-16 text-gray-400">
              <div className="text-4xl mb-3">🔍</div>
              <p>No items found</p>
            </div>
          ) : (
            <div className="flex flex-col gap-0">
              {visibleItems.map(item => (
                <MenuItem
                  key={item.id}
                  item={item}
                  qty={cart[item.id]?.qty || 0}
                  onAdd={() => addItem(item.id, item.name, item.price, item.emoji, item.isVeg)}
                  onRemove={() => removeItem(item.id)}
                />
              ))}
            </div>
          )}
        </div>
      </main>

      {/* ── Cart sidebar ── */}
      <CartSidebar />
    </div>
  );
}

function MenuItem({ item, qty, onAdd, onRemove }) {
  return (
    <div className="flex items-center gap-4 py-5 border-b border-gray-100 last:border-0">
      {/* Food image / emoji */}
      <div className="w-24 h-24 rounded-xl bg-white border border-gray-100 flex items-center justify-center flex-shrink-0 shadow-sm overflow-hidden">
  {item.image ? (
    <img src={item.image} alt={item.name} className="w-full h-full object-cover" />
  ) : (
    <span className="text-4xl">{item.emoji}</span>
  )}
</div>

      {/* Details */}
      <div className="flex-1 min-w-0">
        <div className="flex items-center gap-2 mb-1">
          {/* Veg/Non-veg dot */}
          <div className={`veg-dot ${item.isVeg ? 'veg' : 'nonveg'}`} />
          <h3 className="font-semibold text-gray-900 text-sm">{item.name}</h3>
        </div>
        <p className="text-xs text-gray-500 leading-relaxed mb-2 line-clamp-2">{item.desc}</p>
        <p className="text-base font-bold text-red-600">₹{item.price}</p>
      </div>

      {/* Add / Qty control */}
      <div className="flex-shrink-0 flex items-center">
        {qty === 0 ? (
          <button
            onClick={onAdd}
            className="bg-red-600 hover:bg-red-700 text-white text-sm font-semibold px-5 py-2 rounded-xl transition-colors"
          >
            + Add
          </button>
        ) : (
          <div className="flex items-center gap-3 bg-red-50 border border-red-100 rounded-xl px-3 py-1.5">
            <button
              onClick={onRemove}
              className="w-7 h-7 rounded-lg bg-white border border-red-200 text-red-600 font-bold text-lg flex items-center justify-center hover:bg-red-50 transition-colors"
            >
              −
            </button>
            <span className="text-sm font-bold text-red-700 min-w-[16px] text-center">{qty}</span>
            <button
              onClick={onAdd}
              className="w-7 h-7 rounded-lg bg-red-600 text-white font-bold text-lg flex items-center justify-center hover:bg-red-700 transition-colors"
            >
              +
            </button>
          </div>
        )}
      </div>
    </div>
  );
}
